/* ═══════════════════════════════════════════════════════════════
   LOGIC.JS  —  Stappenteller  v3.0  (clean rewrite)
   Cockpit Framework — swappable logica

   ARCHITECTUUR:
     GPS_BUS.onFix()  → ruwe fix → smoothing → snelheidsvenster → stappen
     APP.onTabChange  → tab-specifieke acties
     LOGIC_INIT()     → bootstrap, aangeroepen door app.js

   KNOPPEN:
     toggleSession()  → START / PAUZE wisselknop
     stopAndReset()   → STOP + reset sessie naar nul
     resetDay()       → dagteller wissen

   FILTERS (in volgorde):
     1. Accuratesse    > 50m     → weggooien
     2. Jitter-smooth  mediaan 5 → stabiele positie
     3. Afstand        < 1m      → ruis, skip
     4. Afstand        > 150m    → teleport, skip
     5. Snelheid       < 0.37 m/s → stilstand, skip
     6. Snelheid       > 1.944 m/s → te snel (>7km/u), skip

   STAP-BEREKENING:
     GPS meet paslengte (linker→linker voet = 2 stappen).
     Stappen = round(dist / (staplengte × 2)) × 2
   ═══════════════════════════════════════════════════════════════ */

'use strict';

/* ── CONSTANTEN ─────────────────────────────────────────────────── */
const STEP_STORAGE_KEY    = 'cockpit_dag_v3';
const SESSION_STORAGE_KEY = 'cockpit_sessie_v3';
const STEPLEN_KEY         = 'cockpit_staplengte_v3';

const DEFAULT_STEP_M  = 0.67;   /* standaard staplengte in meter */
const STRIDE_FACTOR   = 2;      /* 1 pas = 2 stappen             */

const MIN_DIST_M      = 1.0;    /* min afstand per fix-interval  */
const MAX_DIST_M      = 150.0;  /* max afstand per fix-interval  */
const MIN_SPEED_MS    = 0.37;   /* min wandelsnelheid m/s        */
const MAX_SPEED_MS    = 1.944;  /* max wandelsnelheid m/s (7km/u)*/
const ACCURACY_LIMIT  = 50;     /* max GPS-onnauwkeurigheid in m */
const JITTER_N        = 5;      /* mediaanbuffer grootte         */
const BLACKBOX_MS     = 3000;   /* zwarte doos interval          */
const EARTH_R         = 6371000;/* aardstraal meter              */

/* ── STAAT ──────────────────────────────────────────────────────── */
let _stepLen    = DEFAULT_STEP_M;
let _jitterBuf  = [];           /* ringbuffer voor mediaan-smoothing */
let _prevLat    = null;
let _prevLng    = null;
let _prevTs     = null;
let _lastSaveTs = 0;

/* Sessie-state — alles in één object, makkelijk te snapshot-ten */
const S = {
  active:      false,   /* meting loopt */
  paused:      false,   /* meting gepauzeerd */
  steps:       0,
  meters:      0,
  startTs:     null,
  pausedMs:    0,       /* gecumuleerde pauzetijd in ms */
  pauseStartTs:null,    /* tijdstip waarop pauze begon */
  fixCount:    0,
  speedMs:     null,    /* laatste gemeten snelheid */
  restored:    false
};

let dayData = { date: _todayStr(), steps: 0, meters: 0 };

/* ── HULPFUNCTIES ───────────────────────────────────────────────── */
function _todayStr() {
  return new Date().toLocaleDateString('nl-BE');
}

function _haversine(lat1, lng1, lat2, lng2) {
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLng = (lng2 - lng1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2
          + Math.cos(lat1*Math.PI/180) * Math.cos(lat2*Math.PI/180) * Math.sin(dLng/2)**2;
  return EARTH_R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
}

/* Mediaan-smoothing: voeg fix toe aan buffer, retourneer mediaan-positie.
   Buffer wordt ALLEEN gevuld als sessie actief is.                        */
function _smooth(lat, lng) {
  _jitterBuf.push({ lat, lng });
  if (_jitterBuf.length > JITTER_N) _jitterBuf.shift();
  const n = _jitterBuf.length;
  if (n < 2) return { lat, lng };
  const sortedLat = [..._jitterBuf].map(p=>p.lat).sort((a,b)=>a-b);
  const sortedLng = [..._jitterBuf].map(p=>p.lng).sort((a,b)=>a-b);
  const mid = Math.floor(n/2);
  return { lat: sortedLat[mid], lng: sortedLng[mid] };
}

function _fmtDuration(ms) {
  const s = Math.floor(ms/1000);
  const h = Math.floor(s/3600), m = Math.floor((s%3600)/60), sc = s%60;
  const p = n => String(n).padStart(2,'0');
  return h > 0 ? p(h)+':'+p(m)+':'+p(sc) : p(m)+':'+p(sc);
}

function _fmtDist(m) {
  return m >= 1000 ? (m/1000).toFixed(2)+' km' : Math.round(m)+' m';
}

/* Actieve duur = totale tijd - pauzetijd */
function _activeDuration() {
  if (!S.startTs) return 0;
  const totalMs = Date.now() - S.startTs;
  const pauseMs = S.pausedMs + (S.paused && S.pauseStartTs ? Date.now() - S.pauseStartTs : 0);
  return Math.max(0, totalMs - pauseMs);
}

/* ── LOCALSTORAGE ───────────────────────────────────────────────── */
function _loadDay() {
  try {
    const raw = localStorage.getItem(STEP_STORAGE_KEY);
    if (raw) {
      const p = JSON.parse(raw);
      if (p && p.date === _todayStr()) { dayData = p; return; }
    }
  } catch(e) {}
  dayData = { date: _todayStr(), steps:0, meters:0 };
}

function _saveDay() {
  try { localStorage.setItem(STEP_STORAGE_KEY, JSON.stringify(dayData)); } catch(e) {}
}

function _saveBlackBox() {
  if (!S.active) return;
  const now = Date.now();
  if (now - _lastSaveTs < BLACKBOX_MS) return;
  _lastSaveTs = now;
  try {
    localStorage.setItem(SESSION_STORAGE_KEY, JSON.stringify({
      steps: S.steps, meters: S.meters, startTs: S.startTs,
      pausedMs: S.pausedMs, savedAt: now,
      prevLat: _prevLat, prevLng: _prevLng,
      daySteps: dayData.steps, dayMeters: dayData.meters, dayDate: dayData.date
    }));
  } catch(e) {}
}

function _clearBlackBox() {
  try { localStorage.removeItem(SESSION_STORAGE_KEY); } catch(e) {}
}

function _restoreBlackBox() {
  try {
    const raw = localStorage.getItem(SESSION_STORAGE_KEY);
    if (!raw) return false;
    const snap = JSON.parse(raw);
    if (!snap || !snap.savedAt || Date.now() - snap.savedAt > 86400000) {
      _clearBlackBox(); return false;
    }
    S.steps   = snap.steps   || 0;
    S.meters  = snap.meters  || 0;
    S.startTs = snap.startTs || Date.now();
    S.pausedMs= snap.pausedMs|| 0;
    S.active  = true;
    S.paused  = true;   /* herstel altijd als gepauzeerd zodat gebruiker bewust hervat */
    S.restored= true;
    _prevLat  = snap.prevLat || null;
    _prevLng  = snap.prevLng || null;
    if (snap.dayDate === _todayStr()) {
      dayData.steps  = snap.daySteps  || dayData.steps;
      dayData.meters = snap.dayMeters || dayData.meters;
    }
    console.log('[BlackBox] Hersteld:', S.steps, 'stappen');
    return true;
  } catch(e) { _clearBlackBox(); return false; }
}

/* ── GPS_BUS CALLBACK ───────────────────────────────────────────── */
GPS_BUS.onFix((lat, lng, accuracy, raw) => {
  S.fixCount++;

  /* SW-gecachte fix na heropen scherm — geen stappen, wel UI bijwerken */
  if (raw === null) { _updateUI(); return; }

  /* Filter 1: slechte accuratesse — stop hier */
  if (accuracy > ACCURACY_LIMIT) { _updateUI(); return; }

  /* Smooth altijd (ook buiten sessie) zodat buffer al gevuld is bij start */
  const pos = _smooth(lat, lng);

  /* Alleen stappen tellen als sessie actief EN niet gepauzeerd */
  if (!S.active || S.paused) {
    /* Positie bijhouden als referentie — zodat bij hervatten
       de eerste afstand correct is vanaf de pauzepositie       */
    _prevLat = pos.lat; _prevLng = pos.lng; _prevTs = Date.now();
    _updateUI();
    return;
  }

  /* Eerste fix na start: sla op als startpunt, tel nog niets */
  if (_prevLat === null) {
    _prevLat = pos.lat; _prevLng = pos.lng; _prevTs = Date.now();
    _updateUI();
    return;
  }

  const now        = Date.now();
  const dist       = _haversine(_prevLat, _prevLng, pos.lat, pos.lng);
  const elapsedSec = (now - _prevTs) / 1000;
  const speedMs    = elapsedSec > 0 ? dist / elapsedSec : 0;
  S.speedMs        = speedMs;

  /* Filter 2: afstandsvenster */
  if (dist >= MIN_DIST_M && dist <= MAX_DIST_M) {

    /* Filter 3: snelheidsvenster */
    if (speedMs >= MIN_SPEED_MS && speedMs <= MAX_SPEED_MS) {
      const strideLenM = _stepLen * STRIDE_FACTOR;
      const newPaces   = Math.round(dist / strideLenM);
      const newSteps   = newPaces * STRIDE_FACTOR;

      if (newSteps > 0) {
        S.steps       += newSteps;
        S.meters      += dist;
        dayData.steps += newSteps;
        dayData.meters+= dist;
        _saveDay();
        _saveBlackBox();
        console.log(`[Stap] +${newSteps} stappen | dist=${dist.toFixed(1)}m | ${(speedMs*3.6).toFixed(1)}km/u | totaal=${S.steps}`);
      }
    }
  }

  /* Positie altijd bijwerken — ook als geen stappen geteld */
  _prevLat = pos.lat; _prevLng = pos.lng; _prevTs = now;
  _updateUI();
});

GPS_BUS.onError((_code, msg) => {
  const el = document.getElementById('step-gps-status');
  if (el) { el.innerText = msg; el.style.color = 'var(--danger-red)'; }
});

/* ── KNOPPEN ────────────────────────────────────────────────────────
   toggleSession() — START → PAUZE → HERVAT (wisselknop)
   stopAndReset()  — STOP en wis sessie
   ─────────────────────────────────────────────────────────────── */
async function toggleSession() {
  if (!S.active) {
    /* ── START ── */
    await _initAudio();
    _startAudioLoop();

    if (!S.restored) {
      S.steps = 0; S.meters = 0;
      S.startTs = Date.now(); S.pausedMs = 0;
    }
    S.active   = true;
    S.paused   = false;
    S.restored = false;
    _jitterBuf = [];   /* buffer leegmaken bij verse start */
    /* _prevLat/_prevLng behouden van GPS-loop zodat eerste stap correct is */
    console.log('[Toggle] START');

  } else if (!S.paused) {
    /* ── PAUZE ── */
    S.paused       = true;
    S.pauseStartTs = Date.now();
    console.log('[Toggle] PAUZE');

  } else {
    /* ── HERVAT ── */
    S.pausedMs   += Date.now() - (S.pauseStartTs || Date.now());
    S.paused      = false;
    S.pauseStartTs= null;
    /* Reset prevLat/Lng naar huidige positie zodat de pauze-verplaatsing
       niet als stappen wordt geteld                                       */
    if (APP.gps.hasfix) {
      _prevLat = APP.gps.lat;
      _prevLng = APP.gps.lng;
      _prevTs  = Date.now();
      _jitterBuf = [];
    }
    console.log('[Toggle] HERVAT');
  }

  _updateUI();
}

function stopAndReset() {
  _stopAudioLoop();
  _clearBlackBox();
  S.active = false; S.paused = false;
  S.steps  = 0; S.meters = 0;
  S.startTs= null; S.pausedMs = 0; S.pauseStartTs = null;
  S.speedMs= null; S.restored = false; S.fixCount = 0;
  _prevLat = APP.gps.lat; _prevLng = APP.gps.lng; _prevTs = null;
  _jitterBuf = [];
  console.log('[Toggle] STOP + RESET');
  _updateUI();
}

function resetDay() {
  if (!confirm('Dagelijkse teller resetten naar nul?')) return;
  dayData = { date: _todayStr(), steps:0, meters:0 };
  _saveDay(); _updateUI();
}

/* ── AUDIO KEEPALIVE ────────────────────────────────────────────── */
const _SILENT_WAV_B64 = '';
const _SILENT_WAV_URL = 'data:audio/wav;base64,' + _SILENT_WAV_B64;

let _audioCtx = null, _audioSource = null, _audioActive = false;

async function _initAudio() {
  if (_audioCtx) return;
  try {
    _audioCtx = new (window.AudioContext || window.webkitAudioContext)();
    const resp = await fetch(_SILENT_WAV_URL);
    const buf  = await resp.arrayBuffer();
    _audioCtx._silentBuf = await _audioCtx.decodeAudioData(buf);
  } catch(e) { console.warn('[Audio] Init mislukt:', e.message); _audioCtx = null; }
}

function _startAudioLoop() {
  if (!_audioCtx || !_audioCtx._silentBuf || _audioActive) return;
  try {
    _audioSource = _audioCtx.createBufferSource();
    _audioSource.buffer = _audioCtx._silentBuf;
    _audioSource.loop   = true;
    _audioSource.connect(_audioCtx.destination);
    _audioSource.start(0);
    _audioActive = true;
    if ('mediaSession' in navigator) {
      navigator.mediaSession.metadata = new MediaMetadata({
        title: 'GPS Tracking', artist: 'Stappenteller', album: 'Achtergrond'
      });
      navigator.mediaSession.setActionHandler('play',  () => { if (_audioCtx.state==='suspended') _audioCtx.resume(); });
      navigator.mediaSession.setActionHandler('pause', () => { setTimeout(()=>{ if (_audioCtx.state==='suspended') _audioCtx.resume(); },500); });
      navigator.mediaSession.playbackState = 'playing';
    }
  } catch(e) { _audioActive = false; }
}

function _stopAudioLoop() {
  if (!_audioActive || !_audioSource) return;
  try { _audioSource.stop(); _audioSource.disconnect(); } catch(e) {}
  _audioSource = null; _audioActive = false;
  if ('mediaSession' in navigator) navigator.mediaSession.playbackState = 'none';
}

/* ── CONFIG ─────────────────────────────────────────────────────── */
function saveStepLen() {
  const inp = document.getElementById('cfg-step-len-input'); if (!inp) return;
  const v = parseFloat(inp.value);
  if (isNaN(v) || v < 0.30 || v > 1.20) {
    alert('Staplengte moet tussen 0.30m en 1.20m liggen.'); return;
  }
  _stepLen = v;
  try { localStorage.setItem(STEPLEN_KEY, String(_stepLen)); } catch(e) {}
  _updateUI();
  const s = document.getElementById('cfg-step-status');
  if (s) { s.innerText='Opgeslagen: '+_stepLen.toFixed(2)+'m (pas: '+(_stepLen*2).toFixed(2)+'m)'; s.className='cfg-status ok'; s.style.display='block'; }
}

/* ── UI UPDATE ──────────────────────────────────────────────────── */
function _updateUI() {
  const now = new Date();
  const pad = n => String(n).padStart(2,'0');

  /* Klokken */
  const utcEl = document.getElementById('utc-time');
  if (utcEl) utcEl.innerText = [now.getUTCHours(),now.getUTCMinutes(),now.getUTCSeconds()].map(pad).join(':');
  const locEl = document.getElementById('local-time');
  if (locEl) locEl.innerText = now.toLocaleTimeString('nl-BE');
  const dateEl = document.getElementById('date-display');
  if (dateEl) dateEl.innerText = now.toLocaleDateString('nl-BE',{weekday:'long',day:'numeric',month:'long',year:'numeric'});

  /* Sessie stappen + afstand */
  const ssEl = document.getElementById('session-steps');
  if (ssEl) ssEl.innerText = S.steps.toLocaleString('nl-BE');
  const sdEl = document.getElementById('session-dist');
  if (sdEl) sdEl.innerText = _fmtDist(S.meters);

  /* Duur (exclusief pauzetijd) */
  const stEl = document.getElementById('session-duration');
  if (stEl) stEl.innerText = S.startTs ? _fmtDuration(_activeDuration()) : '--:--';

  /* Snelheid */
  const spEl = document.getElementById('session-speed');
  if (spEl) {
    if (S.active && !S.paused && S.speedMs !== null) {
      spEl.innerText = (S.speedMs * 3.6).toFixed(1) + ' km/u';
    } else {
      spEl.innerText = '--';
    }
  }

  /* GPS status + toestand */
  const gpsEl = document.getElementById('step-gps-status');
  if (gpsEl) {
    if (!APP.gps.hasfix) {
      gpsEl.innerText = 'Wachten op GPS fix...';
      gpsEl.style.color = 'var(--warn-orange)';
    } else if (S.active && !S.paused && S.speedMs !== null) {
      const kmh = (S.speedMs * 3.6).toFixed(1);
      const staat = S.speedMs < MIN_SPEED_MS ? '⏸ STILSTAND'
                  : S.speedMs > MAX_SPEED_MS ? '🚫 TE SNEL'
                                              : '🚶 WANDELEN';
      const kleur = S.speedMs < MIN_SPEED_MS ? 'var(--warn-orange)'
                  : S.speedMs > MAX_SPEED_MS ? 'var(--danger-red)'
                                              : 'var(--glow-green)';
      gpsEl.innerText = staat + '  ' + kmh + ' km/u  ±' + Math.round(APP.gps.accuracy) + 'm';
      gpsEl.style.color = kleur;
    } else {
      gpsEl.innerText = 'GPS fix: ±' + Math.round(APP.gps.accuracy) + 'm  (' + S.fixCount + ' fixes)';
      gpsEl.style.color = 'var(--glow-green)';
    }
  }

  /* Audio status */
  const audioEl = document.getElementById('audio-status');
  if (audioEl) {
    audioEl.innerText  = _audioActive ? 'AUDIO: AAN' : '--';
    audioEl.style.color= _audioActive ? 'var(--glow-green)' : '#444';
  }

  /* Dag totaal */
  const dsEl = document.getElementById('day-steps');
  if (dsEl) dsEl.innerText = dayData.steps.toLocaleString('nl-BE');
  const ddEl = document.getElementById('day-dist');
  if (ddEl) ddEl.innerText = _fmtDist(dayData.meters);
  const pct = Math.min(100, Math.round(dayData.steps / 100));
  const goalEl = document.getElementById('day-goal-pct');
  if (goalEl) { goalEl.innerText=pct+'%'; goalEl.style.color=pct>=100?'var(--glow-green)':pct>=50?'var(--accent-gold)':'var(--warn-orange)'; }
  const barEl = document.getElementById('day-goal-bar');
  if (barEl) barEl.style.width = pct + '%';

  /* ── WISSELKNOP logica ──
     3 toestanden:  NIET ACTIEF → START (groen)
                    ACTIEF       → PAUZE (oranje)
                    GEPAUZEERD   → HERVAT (blauw) */
  const btnEl = document.getElementById('session-toggle-btn');
  if (btnEl) {
    if (!S.active) {
      btnEl.innerText = '▶  START METING';
      btnEl.style.background  = 'rgba(0,255,153,0.12)';
      btnEl.style.borderColor = 'var(--glow-green)';
      btnEl.style.color       = 'var(--glow-green)';
    } else if (!S.paused) {
      btnEl.innerText = '⏸  PAUZE';
      btnEl.style.background  = 'rgba(255,153,0,0.12)';
      btnEl.style.borderColor = 'var(--warn-orange)';
      btnEl.style.color       = 'var(--warn-orange)';
    } else {
      btnEl.innerText = '▶  HERVAT';
      btnEl.style.background  = 'rgba(68,136,255,0.12)';
      btnEl.style.borderColor = 'var(--home-blue)';
      btnEl.style.color       = 'var(--home-blue)';
    }
  }

  /* Herstel-indicator */
  const restEl = document.getElementById('restored-indicator');
  if (restEl) restEl.style.display = S.restored ? 'block' : 'none';

  /* Config staplengte display */
  const slEl = document.getElementById('cfg-step-len-display');
  if (slEl) slEl.innerText = _stepLen.toFixed(2)+'m  (pas: '+(_stepLen*2).toFixed(2)+'m)';

  /* Config wake-lock status */
  const wlEl = document.getElementById('cfg-wake-status');
  if (wlEl) {
    const ind = document.getElementById('wake-lock-indicator');
    wlEl.innerText = (ind && ind.style.opacity === '1') ? 'Actief' : 'Niet actief';
  }
}

/* ── TAB CHANGE ─────────────────────────────────────────────────── */
APP.onTabChange = function(viewId) {
  if (viewId === 'config') {
    const inp = document.getElementById('cfg-step-len-input');
    if (inp) inp.value = _stepLen.toFixed(2);
  }
};

/* ── LOGIC_INIT ─────────────────────────────────────────────────── */
function LOGIC_INIT() {
  _loadDay();

  /* Laad opgeslagen staplengte */
  try {
    const s = localStorage.getItem(STEPLEN_KEY);
    if (s) { const v=parseFloat(s); if(v>=0.30&&v<=1.20) _stepLen=v; }
  } catch(e) {}

  /* Zwarte doos herstel */
  const restored = _restoreBlackBox();
  if (restored) {
    const restEl = document.getElementById('restored-indicator');
    if (restEl) { restEl.style.display='block'; restEl.innerText='Sessie hersteld ('+S.steps+' stappen bewaard) — druk HERVAT om door te gaan'; }
  }

  _updateUI();
  setInterval(_updateUI, 1000);
  console.log('[Stappenteller v3] Gestart. Staplengte:', _stepLen+'m | Paslengte:', (_stepLen*2).toFixed(2)+'m');
}
